-- V13__seed_realistic_movie_dataset.sql
-- Clean up all existing mock films, categories, and episodes to ensure clean IDs and relationships.
DELETE FROM films;

-- 1. Ensure categories are populated correctly with fixed IDs
ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;

-- Update categories serial sequence
SELECT setval(pg_get_serial_sequence('categories', 'id'), COALESCE(MAX(id), 1)) FROM categories;

-- 2. Seed realistic movie and series metadata

SELECT setval(pg_get_serial_sequence('films', 'id'), COALESCE(MAX(id), 1)) FROM films;

-- 3. Link films to categories

-- 4. Seed episodes for films

SELECT setval(pg_get_serial_sequence('episodes', 'id'), COALESCE(MAX(id), 1)) FROM episodes;


