(2, 'Lãng mạn',            'Phim tình cảm lãng mạn'),
(3, 'Kinh dị',             'Phim kinh dị, rùng rợn'),
(4, 'Hài hước',            'Phim hài giải trí'),
(5, 'Khoa học viễn tưởng', 'Phim sci-fi, viễn tưởng'),
(6, 'Hoạt hình',           'Phim hoạt hình cho mọi lứa tuổi'),
(7, 'Tài liệu',            'Phim tài liệu'),
(8, 'Thể thao',            'Phim thể thao')
INSERT INTO films (id, title, description, thumbnail_url, trailer_url, release_year, is_premium, type, badge) VALUES
(1, 'Space/Time', 'After a fatal test shuts down their project, a disgraced team of scientists enters the criminal underworld to rebuild a forbidden space-bending engine that could rescue humanity or annihilate it entirely.', 'https://image.tmdb.org/t/p/w500/uje1ecKMnNpZp0at5TxlvVgVXqI.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, TRUE, 'SERIES', NULL),
(2, 'Deathstalker', 'A powerful swordsman known as Deathstalker recovers a cursed amulet from a corpse-strewn battlefield. Marked by dark magic and hunted by monstrous assassins, he must face the rising evil and break the curse.', 'https://image.tmdb.org/t/p/w500/nEI3DnzQC1afAjJOAizx6UX27pL.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(3, 'Zootopia 2', 'After cracking the biggest case in Zootopia''s history, rookie cops Judy Hopps and Nick Wilde find themselves on the twisting trail of a great mystery when Gary De''Snake arrives and turns the animal metropolis upside down. To crack the case, Judy and Nick must go undercover to unexpected new parts of town, where their growing partnership is tested like never before.', 'https://image.tmdb.org/t/p/w500/oJ7g2CifqpStmoYQyaLQgEU32qO.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(4, 'The Shadow''s Edge', 'Macau Police brings the tracking expert police officer out of retirement to help catch a dangerous group of professional thieves.', 'https://image.tmdb.org/t/p/w500/e0RU6KpdnrqFxDKlI3NOqN8nHL6.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(5, 'The Housemaid', 'Trying to escape her past, Millie Calloway accepts a job as a live-in housemaid for the wealthy Nina and Andrew Winchester. But what begins as a dream job quickly unravels into something far more dangerous—a sexy, seductive game of secrets, scandal, and power.', 'https://image.tmdb.org/t/p/w500/cWsBscZzwu5brg9YjNkGewRUvJX.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, TRUE, 'SINGLE', NULL),
(6, 'Predator: Badlands', 'Cast out from his clan, a young Predator finds an unlikely ally in a damaged android and embarks on a treacherous journey in search of the ultimate adversary.', 'https://image.tmdb.org/t/p/w500/erTRAi241eYF4K8KoGGOI8kFPox.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SERIES', NULL),
(7, 'Avatar: Fire and Ash', 'In the wake of the devastating war against the RDA and the loss of their eldest son, Jake Sully and Neytiri face a new threat on Pandora: the Ash People, a violent and power-hungry Na''vi tribe led by the ruthless Varang. Jake''s family must fight for their survival and the future of Pandora in a conflict that pushes them to their emotional and physical limits.', 'https://image.tmdb.org/t/p/w500/bRBeSHfGHwkEpImlhxPmOcUsaeg.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(8, 'War of the Worlds', 'Will Radford is a top analyst for Homeland Security who tracks potential threats through a mass surveillance program, until one day an attack by an unknown entity leads him to question whether the government is hiding something from him... and from the rest of the world.', 'https://image.tmdb.org/t/p/w500/yvirUYrva23IudARHn3mMGVxWqM.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(9, 'Marty Supreme', 'Marty Mauser, a young man with a dream no one respects, goes to hell and back in pursuit of greatness.', 'https://image.tmdb.org/t/p/w500/lYWEXbQgRTR4ZQleSXAgRbxAjvq.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, TRUE, 'SINGLE', NULL),
(10, 'Murder at the Embassy', '1934. Private detective Miranda Green investigates a murder perpetrated in the British Embassy in Cairo, where a top secret document was stolen, risking to jeopardize both Buckingham Palace and the peace of the world. All those present in this closed place are suspected: the American photographer, the English student, the American actress, the Egyptian security guard, the ambassador interpreter, the Egyptian gardener and - why not? — the Ambassador himself. But who would have expected that a small group of Nazis would be behind a plot, risking to jeopardize both Buckingham Palace and the peace of the world?', 'https://image.tmdb.org/t/p/w500/3DBmBItPdy0A2ol59jgHhS54Lua.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(11, '96 Minutes', 'Former bomb disposal expert, Song Kang-Ren, and his fiancée, Huang Xin, board a high-speed train that contains a bomb. At the same time, Liu Kai, a well-known physics teacher who was involved in an affair scandal, also boards this same train in order to win back his wife, Ting Juan, who took the prior high-speed rail to return home in frustration…  After all, can the bomb be successfully defused this time? and resolve the crisis?', 'https://image.tmdb.org/t/p/w500/gWKZ1iLhukvLoh8XY2N4tMvRQ2M.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SERIES', NULL),
(12, 'Die''ced: Reloaded', 'Benny escapes an asylum on Halloween, masked as a scarecrow and hungry for blood. In 1980s Seattle, the hunt is on - and no one is safe.', 'https://image.tmdb.org/t/p/w500/haFDZfpKszHq7DXvuQd5Zz7shQW.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(13, 'Demon Slayer: Kimetsu no Yaiba Infinity Castle', 'The Demon Slayer Corps are drawn into the Infinity Castle, where Tanjiro, Nezuko, and the Hashira face terrifying Upper Rank demons in a desperate fight as the final battle against Muzan Kibutsuji begins.', 'https://image.tmdb.org/t/p/w500/fWVSwgjpT2D78VUh6X8UBd2rorW.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, TRUE, 'SINGLE', NULL),
(14, 'Anaconda', 'A group of friends facing mid-life crises head to the rainforest with the intention of remaking their favorite movie from their youth, only to find themselves in a fight for their lives against natural disasters, giant snakes and violent criminals.', 'https://image.tmdb.org/t/p/w500/qxMv3HwAB3XPuwNLMhVRg795Ktp.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(15, 'Hamnet', 'The powerful story of love and loss that inspired the creation of Shakespeare''s timeless masterpiece, Hamlet.', 'https://image.tmdb.org/t/p/w500/vbeyOZm2bvBXcbgPD3v6o94epPX.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(16, 'Bāhubali: The Epic', 'When a mysterious child is found by a tribal couple near a roaring waterfall, they raise him as their own. As he grows, Sivudu is drawn to the world beyond the cliffs, where he discovers the ancient kingdom of Mahishmati, ruled by a cruel tyrant, haunted by rebellion, and bound to his past. What begins as a quest for love soon unravels a legacy of betrayal, sacrifice, and a forgotten prince.', 'https://image.tmdb.org/t/p/w500/z9YIo2qscyaXYgRqIdRJtND3bw8.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SERIES', NULL),
(17, 'Gates of Flesh', 'A group of friends attempt to escape the city after an outbreak of demon-possessions. The friends seek shelter in an abandoned church, but their plans for escape are ruined when one of them becomes possessed.', 'https://image.tmdb.org/t/p/w500/tsu0fapttpwweWhx2GvYFtSCFhi.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, TRUE, 'SINGLE', NULL),
(18, 'A Father''s Miracle', 'After being falsely accused of a terrible crime, Hector, a man with a neurological disability, goes to a secret prison. His goodness conquers the prisoners, who plan to prove their innocence.', 'https://image.tmdb.org/t/p/w500/heC13pt4SV7y3HF5lWNzf0u729j.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(19, 'Dust Bunny', 'Ten-year-old Aurora asks her hitman neighbor to kill the monster under her bed that she claims ate her family. To protect her, he must battle an onslaught of assassins while accepting that some monsters are real.', 'https://image.tmdb.org/t/p/w500/vobigFZFvbYPf6ElYJu07P9rH8C.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(20, 'Now You See Me: Now You Don''t', 'The original Four Horsemen reunite with a new generation of illusionists to take on powerful diamond heiress Veronika Vanderberg, who leads a criminal empire built on money laundering and trafficking. The new and old magicians must overcome their differences to work together on their most ambitious heist yet.', 'https://image.tmdb.org/t/p/w500/oD3Eey4e4Z259XLm3eD3WGcoJAh.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(21, 'David', 'From the songs of his mother’s heart to the whispers of a faithful God, David’s story begins in quiet devotion. When the giant Goliath rises to terrorize a nation, a young shepherd armed with only a sling, a few stones, and unshakable faith steps forward. Pursued by power and driven by purpose, his journey tests the limits of loyalty, love, and courage—culminating in a battle not just for a crown, but for the soul of a kingdom.', 'https://image.tmdb.org/t/p/w500/bESlrLOrsQ9gKzaGQGHXKOyIUtX.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, TRUE, 'SERIES', NULL),
(22, 'Icefall', 'A young Indigenous game warden arrests an infamous poacher only to discover that the poacher knows the location of a plane carrying millions of dollars that has crashed in a frozen lake. When a group of criminals and dirty cops are alerted to the poacher’s whereabouts, the warden and the poacher team up to fight back and escape across the treacherous lake before the ice melts.', 'https://image.tmdb.org/t/p/w500/5Byv6nznAb2Izd0gHpODOXnuSbo.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(23, 'The SpongeBob Movie: Search for SquarePants', 'Desperate to be a big guy, SpongeBob sets out to prove his bravery to Mr. Krabs by following The Flying Dutchman – a mysterious swashbuckling ghost pirate – on a seafaring adventure that takes him to the deepest depths of the deep sea, where no Sponge has gone before.', 'https://image.tmdb.org/t/p/w500/xJnOMMsFASxNiFnG7v3TNIQ3ife.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(24, 'Tales from the Magic Garden', 'Tom (4 years old), Suzanne (8) and Derek (10) spend the weekend with their grandparents. But nothing is as usual: Grandpa seems to be elsewhere; Tom wonders where Grandma has gone, she who always tells him incredible stories; Derek is hard at work renovating the old apple tree hut. So following in the footsteps of her ancestor, Suzanne improvises herself as a storyteller to illuminate the house with imaginary and wonderful stories and try to fill the absence of Grandmother. The movie is an adaptation of three tales written by Arnost Goldflam.', 'https://image.tmdb.org/t/p/w500/6LZJKktqh9jTL27vMU6oxzdvB3W.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(25, 'The Tank', 'A German Tiger tank crew is sent on a dangerous mission to rescue the missing officer Paul von Hardenburg from a top-secret bunker behind enemy lines. As they make their way through the lethal no-man''s land, they must confront not only the enemy, but also their own fears and inner demons. Fueled by the Wehrmacht''s methamphetamine, their mission increasingly becomes a journey into the heart of darkness.', 'https://image.tmdb.org/t/p/w500/65Jr1JAgWlu9em8zHhAfrNJJQBt.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, TRUE, 'SINGLE', NULL),
(26, 'iPossessed', 'A group of celebrating friends make a pact with a demon to stay the night or someone loses their soul, only to find out the demons they are fighting might be the ones they carry inside.', 'https://image.tmdb.org/t/p/w500/kmnaCRTinFPN8iplWgdGQZ52WzY.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SERIES', NULL),
(27, 'Salvation', 'A foster child bonds with a snake-handling Pentecostal community but uncovers sinister truths. She must choose between reporting pastor''s crimes or preserving her newfound support system, risking personal safety for a sense of belonging.', 'https://image.tmdb.org/t/p/w500/k0ux5SqOmCR7b4MUHJL5vY2jNjf.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(28, 'KPop Demon Hunters', 'When K-pop superstars Rumi, Mira and Zoey aren''t selling out stadiums, they''re using their secret powers to protect their fans from supernatural threats.', 'https://image.tmdb.org/t/p/w500/zT7Lhw3BhJbMkRqm9Zlx2YGMsY0.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(29, 'Mission: Impossible - The Final Reckoning', 'Ethan Hunt and team continue their search for the terrifying AI known as the Entity — which has infiltrated intelligence networks all over the globe — with the world''s governments and a mysterious ghost from Hunt''s past on their trail. Joined by new allies and armed with the means to shut the Entity down for good, Hunt is in a race against time to prevent the world as we know it from changing forever.', 'https://image.tmdb.org/t/p/w500/z53D72EAOxGRqdr7KXXWp9dJiDe.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, TRUE, 'SINGLE', NULL),
(30, 'Eye for an Eye', 'Anna, grieving the sudden death of her parents, relocates from New York to a small Florida town to live with the grandmother she has never met. Isolated, vulnerable, and in need of friends, she finds brief solace in the company of two local teens. But when she becomes complicit to their unforgivable act of violence, she finds herself ensnared by Mr. Sandman – the twisted soul of a tormented child who haunts bullies’ dreams before feasting on their eyeballs when they finally wake - Anna must right her wrong before becoming a victim of this gruesome curse.', 'https://image.tmdb.org/t/p/w500/lpepbfVziHJLhVoxTEKs8ok00iu.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(31, 'Holy Ghost', 'A kidnapped girl in Augusta claims her rescuer was Jim, a deceased cop. Detective Wells probes the case as another child vanishes, revealing old murders and raising questions about a ghostly presence.', 'https://image.tmdb.org/t/p/w500/z1lwn6GWAjJ7CSn80ZcURb0Cj4G.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SERIES', NULL),
(32, 'Dracula', 'In late 15th-century Eastern Europe, Prince Vlad II’s bride is brutally murdered. As a result, he renounces God and damns Heaven itself. Cursed with eternal life, Vlad is reborn as Dracula, an immortal warlord who defies fate in a blood-soaked crusade to wrench his lost love back from death.', 'https://image.tmdb.org/t/p/w500/libhghrUSBSEdHgF9uP1SQES0nQ.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(33, 'Kulong', 'Three friends retreat to a resort to collaborate on a daring screenplay for a contest. Faced with the challenge of writing about passion despite their own dry spells, their journey soon blurs the line between imagination and experience.', 'https://image.tmdb.org/t/p/w500/AnzrE2WHg3DtZrtmB9AnEbAh17m.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2024, TRUE, 'SINGLE', NULL),
(34, 'Sisu: Road to Revenge', 'Returning to the house where his family was brutally murdered during the war, "the man who refuses to die" dismantles it, loads it on a truck, and is determined to rebuild it somewhere safe in their honor. When the commander who killed his family comes back hellbent on finishing the job, a relentless, eye-popping cross-country chase ensues.', 'https://image.tmdb.org/t/p/w500/jNsttCWZyPtW66MjhUozBzVsRb7.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(35, 'Power of Love', 'Saara and Robert are living a love that is free from traditional conventions and role models. They set off to an extensive summer holiday on a lonely island in the Finnish archipelago where the tension between them escalates and becomes a fight for survival.', 'https://image.tmdb.org/t/p/w500/dqUQ0xyMaJn5g7RYqCMykbXXW4C.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2023, FALSE, 'SINGLE', NULL),
(36, 'Sinners', 'Trying to leave their troubled lives behind, twin brothers return to their hometown to start again, only to discover that an even greater evil is waiting to welcome them back.', 'https://image.tmdb.org/t/p/w500/qTvFWCGeGXgBRaINLY1zqgTPSpn.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SERIES', NULL),
(37, 'Trap House', 'An undercover DEA agent and his partner embark on a game of cat and mouse with an audacious, and surprising group of thieves - their own rebellious teenagers, who have begun robbing from a dangerous cartel, using their parents'' tactics and top-secret intel to do it.', 'https://image.tmdb.org/t/p/w500/6tpAPeuuqbVnYWWPoOLEDLSBU7a.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, TRUE, 'SINGLE', NULL),
(38, 'Strangers', 'Seeking revenge on her abusive husband, a woman''s life takes a dark turn when she meets a mysterious hitman. Drawn into a whirlwind romance, she spirals into a dangerous vigilante spree. As the body count rises, she begins to unravel the true nature of her partner and the secrets they both conceal.', 'https://image.tmdb.org/t/p/w500/v6hYeC1asK2ZRU7Ygukn4tV1zlS.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2024, FALSE, 'SINGLE', NULL),
(39, 'The Dinner', 'Spain, April 15, 1939. With the Civil War concluded, and with the intention of celebrating his victory, General Franco attends a dinner with his generals at the Palace Hotel.', 'https://image.tmdb.org/t/p/w500/8Ct1yY0ClGwgQpnsipRcaFC27xF.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(40, 'Who Wants to Marry an Astronaut?', 'David is a dopey hopeless romantic with a hippy mother and a best friend who also works for him. After fifteen years of living together, on an impulse, he decides to ask his partner to marry him in Las Vegas. His anticipation for the dream wedding and trip is crushed when his partner answers ‘No’. David decides to power through with his plans and now he has ten days to find the knight in shining armor that will marry him in Las Vegas.', 'https://image.tmdb.org/t/p/w500/8kyqyI6mQmIVdLPRvIaFskVIcQW.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(41, 'Exit 8', 'A man trapped in an endless sterile subway passageway sets out to find Exit 8. The rules of his quest are simple: do not overlook anything out of the ordinary. If you discover an anomaly, turn back immediately. If you don’t, carry on. Then leave from Exit 8. But even a single oversight will send him back to the beginning. Will he ever reach his goal and escape this infinite corridor?', 'https://image.tmdb.org/t/p/w500/cWHmaDXnRPAC9HBbjUBfJW7MxO0.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, TRUE, 'SERIES', NULL),
(42, 'No Other Choice', 'After being laid off and humiliated by a ruthless job market, a veteran paper mill manager descends into violence in a desperate bid to reclaim his dignity.', 'https://image.tmdb.org/t/p/w500/sBpxTGLzKnvPSVtL5yQYpSxvKEb.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(43, 'One Battle After Another', 'Washed-up revolutionary Bob exists in a state of stoned paranoia, surviving off-grid with his spirited, self-reliant daughter, Willa. When his evil nemesis resurfaces after 16 years and she goes missing, the former radical scrambles to find her, father and daughter both battling the consequences of his past.', 'https://image.tmdb.org/t/p/w500/lbBWwxBht4JFP5PsuJ5onpMqugW.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(44, 'F1', 'Racing legend Sonny Hayes is coaxed out of retirement to lead a struggling Formula 1 team—and mentor a young hotshot driver—while chasing one more chance at glory.', 'https://image.tmdb.org/t/p/w500/vqBmyAj0Xm9LnS1xe1MSlMAJyHq.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(45, 'Omniscient Reader: The Prophecy', 'Kim Dok-ja, an ordinary man in his 20s, is the only reader of an obscure web novel titled "Three Ways to Survive the Apocalypse". After having read the last chapter, the novel suddenly becomes reality, and its omnipotent hero Yu Jung-hyeok appears before Kim. As the only person who knows how to survive in this world, Kim and his companions strive to save the world by writing his own, new ending.', 'https://image.tmdb.org/t/p/w500/3R3dXO2nm8JyR5NG7SEfii7RzlV.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, TRUE, 'SINGLE', NULL),
(46, 'Frankenstein', 'Dr. Victor Frankenstein, a brilliant but egotistical scientist, brings a creature to life in a monstrous experiment that ultimately leads to the undoing of both the creator and his tragic creation.', 'https://image.tmdb.org/t/p/w500/g4JtvGlQO7DByTI6frUobqvSL3R.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SERIES', NULL),
(47, 'Five Nights at Freddy''s 2', 'One year since the supernatural nightmare at Freddy Fazbear''s Pizza, the stories about what transpired there have been twisted into a campy local legend, inspiring the town''s first ever Fazfest. With the truth kept from her, Abby sneaks out to reconnect with Freddy, Bonnie, Chica, and Foxy, setting into motion a terrifying series of events that will reveal dark secrets about the real origin of Freddy''s, and unleash a decades-hidden horror.', 'https://image.tmdb.org/t/p/w500/udAxQEORq2I5wxI97N2TEqdhzBE.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(48, 'The Great Flood', 'When a raging flood traps a researcher and her young son, a call to a crucial mission puts their escape — and the future of humanity — on the line.', 'https://image.tmdb.org/t/p/w500/1tUOZQDgZaGqZtrB21MieiXARL2.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(49, 'Avatar: The Way of Water', 'Set more than a decade after the events of the first film, learn the story of the Sully family (Jake, Neytiri, and their kids), the trouble that follows them, the lengths they go to keep each other safe, the battles they fight to stay alive, and the tragedies they endure.', 'https://image.tmdb.org/t/p/w500/t6HIqrRAclMCA60NsSmeqe9RmNV.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2022, TRUE, 'SINGLE', NULL),
(50, 'Baby Boy, Baby Girl', 'Josie is a failed startup businesswoman, who is struggling with no permanent job. Ever since she saw her ex-boyfriend Seb escorting a politician and broke up with him three years ago, Josie remains single. Seb, on the other hand, becomes more sophisticated from earning handsomely through Sugar Dating. Josie learns about Seb’s success, prompting her to ask Seb to groom her for Sugar Dating. Once Josie gets a grasp on the work, she will be good at what she does and will not struggle financially anymore. At the same time, Seb’s feelings for her start coming back, but Josie now sees love differently. She thinks that love should only be transactional. It does not help that Josie can’t forget the time when Seb broke her heart.', 'https://image.tmdb.org/t/p/w500/cTi6t2F7i5MjhqRIEBjav6GJLfa.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2023, FALSE, 'SINGLE', NULL),
(51, 'My Fault', 'Noah must leave her city, boyfriend, and friends to move into William Leister''s mansion, the flashy and wealthy husband of her mother Rafaela. As a proud and independent 17 year old, Noah resists living in a mansion surrounded by luxury. However, it is there where she meets Nick, her new stepbrother, and the clash of their strong personalities becomes evident from the very beginning.', 'https://image.tmdb.org/t/p/w500/w46Vw536HwNnEzOa7J24YH9DPRS.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2023, FALSE, 'SERIES', NULL),
(52, 'Jurassic World Rebirth', 'Five years after the events of Jurassic World Dominion, covert operations expert Zora Bennett is contracted to lead a skilled team on a top-secret mission to secure genetic material from the world''s three most massive dinosaurs. When Zora''s operation intersects with a civilian family whose boating expedition was capsized, they all find themselves stranded on an island where they come face-to-face with a sinister, shocking discovery that''s been hidden from the world for decades.', 'https://image.tmdb.org/t/p/w500/1RICxzeoNCAO5NpcRMIgg1XT6fm.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(53, 'Worldbreaker', 'Five years ago, a tear in the fabric of reality brought creatures to our world from an alternate dimension bent on our destruction. A father hides his daughter on an island to keep her safe while he prepares her for survival and the battles to come. But when the world is about to break, no place is safe.', 'https://image.tmdb.org/t/p/w500/7K8w6mdrJp0oaSoKWGyjSZ4Zv2z.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, TRUE, 'SINGLE', NULL),
(54, 'La deuda', 'Lucas, a 47-year-old boy, and Antonia, an old woman, live together in an apartment in the center of the city. Their life goes on as usual until an investment fund acquires the building to turn it into tourist apartments. Lucas tries to get the necessary money to avoid the loss of the house, but a wrong decision will change the rest of their lives.', 'https://image.tmdb.org/t/p/w500/8LFKzVhsPJmIA9v5BVDGGLk3Ltl.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(55, 'Superman', 'Superman, a journalist in Metropolis, embarks on a journey to reconcile his Kryptonian heritage with his human upbringing as Clark Kent.', 'https://image.tmdb.org/t/p/w500/wPLysNDLffQLOVebZQCbXJEv6E6.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(56, 'Bureau 749', 'A traumatized young man with physical abnormalities is forced to join a mysterious bureau to confront a disaster spreading across the earth caused by an unknown creature. He embarks on an adventure uncovering mysteries about his life.', 'https://image.tmdb.org/t/p/w500/flykCMw22y6yv8vKnBjmsW3pneo.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2024, FALSE, 'SERIES', NULL),
(57, 'TRON: Ares', 'A highly sophisticated Program called Ares is sent from the digital world into the real world on a dangerous mission, marking humankind''s first encounter with A.I. beings.', 'https://image.tmdb.org/t/p/w500/chpWmskl3aKm1aTZqUHRCtviwPy.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, TRUE, 'SINGLE', NULL),
(58, 'Wildcat', 'An ex-black ops team reunite to pull off a desperate heist in order to save the life of their leader’s eight-year-old daughter.', 'https://image.tmdb.org/t/p/w500/h893ImjM6Fsv5DFhKJdlZFZIJno.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL),
(59, 'EKS', 'Three compelling stories in one erotic experience. Yen Durano plays three different women in three titillating stories. In a collaboration of three directors: Roman Perez, Jr., Sigrid Polon, and Omar Deroca.', 'https://image.tmdb.org/t/p/w500/gcK3HgN6IHNOviXnX11W6aFLTGv.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2024, FALSE, 'SINGLE', NULL),
(60, 'A Useful Ghost', 'After dying from a respiratory disease, a mother''s spirit possesses a vacuum cleaner to protect her husband when he begins showing the same symptoms.', 'https://image.tmdb.org/t/p/w500/2PteNeb8LYFtZP7eowANUXs9feC.jpg', 'http://localhost:9000/cineflow-media/trailers/sample_trailer.mp4', 2025, FALSE, 'SINGLE', NULL);
